1	import { runScenario, type Scenario } from "./claim-office.js";
2	
3	const KNOWN_ITEM_TYPES = new Set(["sword", "amulet", "staff", "potion", "rune", "moonstone"]);
4	
5	const readStdin = async (): Promise<string> => {
6	  const chunks: Buffer[] = [];
7	  for await (const chunk of process.stdin) {
8	    chunks.push(chunk as Buffer);
9	  }
10	  return Buffer.concat(chunks).toString("utf8");
11	};
12	
13	const validateScenario = (scenario: Scenario): void => {
14	  for (const step of scenario.steps) {
15	    if (step.op === "quote") {
16	      for (const item of step.items) {
17	        if (!KNOWN_ITEM_TYPES.has(item.type)) {
18	          throw new Error(`unknown item type: '${item.type}'`);
19	        }
20	      }
21	    }
22	  }
23	};
24	
25	const main = async (): Promise<void> => {
26	  const input = await readStdin();
27	  const scenario = JSON.parse(input) as Scenario;
28	  validateScenario(scenario);
29	  const result = runScenario(scenario);
30	  process.stdout.write(JSON.stringify(result));
31	};
32	
33	main().catch((error: unknown) => {
34	  const message = error instanceof Error ? error.message : String(error);
35	  process.stderr.write(`${message}\n`);
36	  process.exit(1);
37	});
