1	export interface Customer {
2	  yearsWithMHPCO: number;
3	}
4	
5	export interface Item {
6	  type: string;
7	  material?: string;
8	  enchantment?: number;
9	  cursed?: boolean;
10	}
11	
12	export interface QuoteStep {
13	  op: "quote";
14	  items: Item[];
15	}
16	
17	export interface Damage {
18	  itemType: string;
19	  amount: number;
20	}
21	
22	export interface Incident {
23	  cause: string;
24	  damages: Damage[];
25	}
26	
27	export interface ClaimStep {
28	  op: "claim";
29	  policy: number;
30	  incident: Incident;
31	}
32	
33	export type Step = QuoteStep | ClaimStep;
34	
35	export interface Scenario {
36	  customer: Customer;
37	  steps: Step[];
38	}
39	
40	export interface QuoteResult {
41	  premium: number;
42	}
43	
44	export interface ClaimResult {
45	  payout: number;
46	  remainingCap: number;
47	}
48	
49	export type StepResult = QuoteResult | ClaimResult;
50	
51	export interface ScenarioResult {
52	  results: StepResult[];
53	}
54	
55	const PROCESSING_FEE = 5;
56	const DEDUCTIBLE = 100;
57	const CAP_MULTIPLIER = 2;
58	
59	interface ItemPricing {
60	  basePremium: number;
61	  insuranceValue: number;
62	}
63	
64	const ITEM_PRICING: Record<string, ItemPricing> = {
65	  sword: { basePremium: 100, insuranceValue: 1000 },
66	  amulet: { basePremium: 60, insuranceValue: 600 },
67	  staff: { basePremium: 80, insuranceValue: 800 },
68	  potion: { basePremium: 40, insuranceValue: 400 },
69	  rune: { basePremium: 25, insuranceValue: 250 },
70	  moonstone: { basePremium: 25, insuranceValue: 250 },
71	};
72	
73	const pricingFor = (type: string): ItemPricing =>
74	  ITEM_PRICING[type] ?? { basePremium: 0, insuranceValue: 0 };
75	
76	const CURSED_SURCHARGE_RATE = 0.5;
77	const HIGH_ENCHANTMENT_THRESHOLD = 5;
78	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
79	const FIRST_INSURANCE_RATE = 0.1;
80	const LOYALTY_THRESHOLD_YEARS = 2;
81	const LOYALTY_DISCOUNT_RATE = 0.2;
82	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
83	
84	const isCursed = (item: Item): boolean => item.cursed === true;
85	const isHighlyEnchanted = (item: Item): boolean =>
86	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
87	
88	const surchargeRate = (item: Item): number =>
89	  (isCursed(item) ? CURSED_SURCHARGE_RATE : 0) +
90	  (isHighlyEnchanted(item) ? HIGH_ENCHANTMENT_SURCHARGE_RATE : 0);
91	
92	const itemBaseValue = (item: Item): number => pricingFor(item.type).basePremium;
93	
94	const itemSurcharge = (item: Item): number =>
95	  itemBaseValue(item) * surchargeRate(item);
96	
97	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
98	const BLOCK_SIZE = 3;
99	const BLOCK_PREMIUM = 60;
100	
101	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
102	
103	const sumBy = <T>(values: T[], measure: (value: T) => number): number =>
104	  values.reduce((sum, value) => sum + measure(value), 0);
105	
106	const groupByType = (items: Item[]): Item[][] => {
107	  const byType = new Map<string, Item[]>();
108	  for (const item of items) {
109	    const group = byType.get(item.type) ?? [];
110	    group.push(item);
111	    byType.set(item.type, group);
112	  }
113	  return [...byType.values()];
114	};
115	
116	const groupPremium = (group: Item[]): number =>
117	  group.length === BLOCK_SIZE ? BLOCK_PREMIUM : sumBy(group, itemBaseValue);
118	
119	const partition = <T>(values: T[], predicate: (value: T) => boolean): [T[], T[]] => {
120	  const matches: T[] = [];
121	  const rest: T[] = [];
122	  for (const value of values) {
123	    (predicate(value) ? matches : rest).push(value);
124	  }
125	  return [matches, rest];
126	};
127	
128	const policyBasePremium = (items: Item[]): number => {
129	  const [components, mainItems] = partition(items, isComponent);
130	  return sumBy(groupByType(components), groupPremium) + sumBy(mainItems, itemBaseValue);
131	};
132	
133	const totalSurcharges = (items: Item[]): number => sumBy(items, itemSurcharge);
134	
135	const loyaltyRate = (customer: Customer): number =>
136	  customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS ? LOYALTY_DISCOUNT_RATE : 0;
137	
138	const followUpRate = (isFollowUp: boolean): number =>
139	  isFollowUp ? FOLLOW_UP_DISCOUNT_RATE : 0;
140	
141	const netPolicyRate = (customer: Customer, isFollowUp: boolean): number =>
142	  FIRST_INSURANCE_RATE - loyaltyRate(customer) - followUpRate(isFollowUp);
143	
144	const quotePremium = (customer: Customer, items: Item[], isFollowUp: boolean): number => {
145	  const base = policyBasePremium(items);
146	  const surcharges = totalSurcharges(items);
147	  const policyAdjustment = base * netPolicyRate(customer, isFollowUp);
148	  return Math.ceil(base + surcharges + policyAdjustment + PROCESSING_FEE);
149	};
150	
151	interface Policy {
152	  items: Item[];
153	  remainingCap: number;
154	}
155	
156	const insuranceSum = (items: Item[]): number =>
157	  sumBy(items, (item) => pricingFor(item.type).insuranceValue);
158	
159	const newPolicy = (items: Item[]): Policy => ({
160	  items,
161	  remainingCap: insuranceSum(items) * CAP_MULTIPLIER,
162	});
163	
164	const HIGH_ENCHANTMENT_DAMAGE_THRESHOLD = 8;
165	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
166	
167	const triggersHalfReimbursement = (item: Item | undefined): boolean =>
168	  item !== undefined && (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_DAMAGE_THRESHOLD;
169	
170	const reimbursementAmount = (item: Item | undefined, damageAmount: number): number =>
171	  triggersHalfReimbursement(item)
172	    ? damageAmount * HIGH_ENCHANTMENT_REIMBURSEMENT_RATE
173	    : damageAmount;
174	
175	const insuredItemFor = (policy: Policy, itemType: string): Item | undefined =>
176	  policy.items.find((item) => item.type === itemType);
177	
178	const damagePayout = (policy: Policy, damage: Damage): number => {
179	  const insuredItem = insuredItemFor(policy, damage.itemType);
180	  return reimbursementAmount(insuredItem, damage.amount) - DEDUCTIBLE;
181	};
182	
183	const countByKey = <T>(values: T[], keyOf: (value: T) => string): Map<string, number> => {
184	  const counts = new Map<string, number>();
185	  for (const value of values) {
186	    const key = keyOf(value);
187	    counts.set(key, (counts.get(key) ?? 0) + 1);
188	  }
189	  return counts;
190	};
191	
192	const validateDamageCounts = (policy: Policy, damages: Damage[]): void => {
193	  const insuredCounts = countByKey(policy.items, (item) => item.type);
194	  const damageCounts = countByKey(damages, (damage) => damage.itemType);
195	  for (const [type, count] of damageCounts) {
196	    if (count > (insuredCounts.get(type) ?? 0)) {
197	      throw new Error(`damages for type '${type}' exceed insured count`);
198	    }
199	  }
200	};
201	
202	const processClaim = (policy: Policy, incident: Incident): ClaimResult => {
203	  validateDamageCounts(policy, incident.damages);
204	  const totalDamagePayout = sumBy(incident.damages, (damage) => damagePayout(policy, damage));
205	  const payout = Math.min(Math.floor(totalDamagePayout), policy.remainingCap);
206	  return { payout, remainingCap: policy.remainingCap - payout };
207	};
208	
209	const handleQuote = (
210	  customer: Customer,
211	  step: QuoteStep,
212	  index: number,
213	  policies: Map<number, Policy>,
214	): QuoteResult => {
215	  const isFollowUp = policies.size > 0;
216	  policies.set(index, newPolicy(step.items));
217	  return { premium: quotePremium(customer, step.items, isFollowUp) };
218	};
219	
220	const handleClaim = (step: ClaimStep, policies: Map<number, Policy>): ClaimResult => {
221	  const policy = policies.get(step.policy)!;
222	  const result = processClaim(policy, step.incident);
223	  policies.set(step.policy, { ...policy, remainingCap: result.remainingCap });
224	  return result;
225	};
226	
227	export const runScenario = (scenario: Scenario): ScenarioResult => {
228	  const policies = new Map<number, Policy>();
229	  const results = scenario.steps.map((step, index): StepResult =>
230	    step.op === "quote"
231	      ? handleQuote(scenario.customer, step, index, policies)
232	      : handleClaim(step, policies),
233	  );
234	  return { results };
235	};
